import React, { useState } from 'react';
import './AddMaterial.css';

const handleAdd = useCallback((newMaterial) => {
  const materialExists = materials.some(
    (material) => material.matid === newMaterial.matid || material.name === newMaterial.name
  );

  if (materialExists) {
    alert('Material ID or name already exists.');
    return;
  }

  fetch('http://localhost:8081/materiallist', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(newMaterial),
  })
    .then((response) => {
      if (response.ok) {
        return response.json();
      } else {
        throw new Error('Error adding material');
      }
    })
    .then(() => {
      fetchData();
    })
    .catch((error) => {
      console.log('Error adding material:', error);
    });
}, [materials]);  

const AddMaterial = ({ handleAdd }) => {
  const [newMaterial, setNewMaterial] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: '',
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewMaterial((prevMaterial) => ({
      ...prevMaterial,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAdd(newMaterial);
    resetForm();
  };

  const resetForm = () => {
    setNewMaterial({
      matid: '',
      name: '',
      description: '',
      unit_of_measure: '',
      price_per_unit: 0,
      recent_vendor: '',
    });
  };

  return (
    <div className="add-material-container">
      <h2 className="add-material-heading">Add Material</h2>
      <form className="add-material-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="matid">Material ID:</label>
            <input
              type="text"
              id="matid"
              name="matid"
              value={newMaterial.matid}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              name="name"
              value={newMaterial.name}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <textarea
              id="description"
              name="description"
              value={newMaterial.description}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="unit_of_measure">Unit of Measure:</label>
            <input
              type="text"
              id="unit_of_measure"
              name="unit_of_measure"
              value={newMaterial.unit_of_measure}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="price_per_unit">Price per Unit:</label>
            <input
              type="number"
              id="price_per_unit"
              name="price_per_unit"
              value={newMaterial.price_per_unit}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="recent_vendor">Recent Vendor:</label>
            <input
              type="text"
              id="recent_vendor"
              name="recent_vendor"
              value={newMaterial.recent_vendor}
              onChange={handleInputChange}
              required
            />
          </div>
        </div>
        <button type="submit" className="add-material-btn">Add</button>
      </form>
    </div>
  );
};

export default AddMaterial;
